import React, { useId } from 'react';
import { Card, CardContent, Box, Typography, Stack } from '@mui/material';
import { ResponsiveChartContainer, LinePlot, ChartsXAxis, ChartsYAxis, ChartsClipPath } from '@mui/x-charts';
import response from './response.json';

interface EngagementTrend {
  day: string;
  engagement: number;
}

interface CommunityMetricsData {
  activeMembers: number;
  postsToday: number;
  engagementTrend: EngagementTrend[];
}

export default function Widget() {
  const data = response.data as CommunityMetricsData;
  const clipPathId = useId();

  return (
    <Card sx={{ width: 'fit-content', minWidth: 350, maxWidth: 450, bgcolor: '#FFFFFF' }} elevation={2}>
      <CardContent sx={{ p: 2.5 }}>
        <Stack spacing={2}>
          <Box>
            <Typography variant="body2" color="text.secondary">
              Active Members
            </Typography>
            <Typography variant="h4" fontWeight={700} sx={{ color: '#FF5722' }}>
              {data.activeMembers.toLocaleString()}
            </Typography>
          </Box>

          <Box>
            <Typography variant="body2" color="text.secondary">
              Posts Today
            </Typography>
            <Typography variant="h4" fontWeight={700} sx={{ color: '#009688' }}>
              {data.postsToday}
            </Typography>
          </Box>

          <Box sx={{ width: '100%', height: 200 }}>
            <ResponsiveChartContainer
              series={[
                {
                  type: 'line',
                  data: data.engagementTrend.map(e => e.engagement),
                  color: '#FF5722',
                  label: 'Engagement',
                },
              ]}
              xAxis={[
                {
                  scaleType: 'band',
                  data: data.engagementTrend.map(e => e.day),
                  id: 'days',
                },
              ]}
              yAxis={[{ id: 'engagement' }]}
            >
              <g clipPath={`url(#${clipPathId})`}>
                <LinePlot />
              </g>
              <ChartsXAxis
                axisId="days"
                tickLabelStyle={{ fontSize: 10, fill: '#6B7280' }}
              />
              <ChartsYAxis
                axisId="engagement"
                tickLabelStyle={{ fontSize: 10, fill: '#6B7280' }}
              />
              <ChartsClipPath id={clipPathId} />
            </ResponsiveChartContainer>
          </Box>
        </Stack>
      </CardContent>
    </Card>
  );
}
